import { useEffect, useState } from 'react';
import API from '../api/axios';

function AdminPage() {
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    API.get('/admin/messages')
      .then((res) => {
        setMessages(res.data);
      })
      .catch((err) => {
        setError(err?.response?.data?.message || 'Unable to load contact messages.');
      })
      .finally(() => setLoading(false));
  }, []);

  return (
    <main className="admin-page">
      <section className="admin-header">
        <h2>Admin Dashboard</h2>
        <p>Contact messages sent through the site appear here for review.</p>
      </section>

      <section className="admin-messages">
        {loading ? (
          <p>Loading messages...</p>
        ) : error ? (
          <p className="error-text">{error}</p>
        ) : messages.length === 0 ? (
          <p>No contact messages have been sent yet.</p>
        ) : (
          <div>
            <p>{messages.length} message{messages.length !== 1 ? 's' : ''}</p>
            <table>
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Message</th>
                  <th>Received</th>
                </tr>
              </thead>
              <tbody>
                {messages.map((message) => (
                  <tr key={message._id}>
                    <td>{message.name}</td>
                    <td>{message.email}</td>
                    <td>{message.message}</td>
                    <td>{new Date(message.createdAt).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>
    </main>
  );
}

export default AdminPage;
